#include<bits/stdc++.h>
using namespace std;
int f[21][1010],n,q,cost[1010],val[1010],m[1010],ans[1010][1010];
void dp(int d,int x)
{
    for(int i=0;i<cost[x];i++)
    {
        deque<pair<int,int>> q;
        q.push_back(make_pair(0,f[d][i]));
        for(int j=1;j*cost[x]+i<=1000;j++)
        {
            while(!q.empty()&&f[d][i+j*cost[x]]-j*val[x]>=q.back().second)
            {
                q.pop_back();
            }
            q.push_back(make_pair(j,f[d][i+j*cost[x]]-j*val[x]));
            while(!q.empty()&&q.front().first<j-m[x])
            {
                q.pop_front();
            }
            f[d][i+j*cost[x]]=max(f[d][i+j*cost[x]],q.front().second+j*val[x]);
        }
    }
}
void dfs(int d,int l,int r)
{
    if(l==r)
    {
        for(int i=0;i<=1000;i++)
        {
            ans[l][i]=f[d-1][i];
        }
        return;
    }
    int mid=(l+r)/2;
    memcpy(f[d],f[d-1],sizeof(f[d]));
    for(int i=mid+1;i<=r;i++)
    {
        dp(d,i);
    }
    dfs(d+1,l,mid);
    memcpy(f[d],f[d-1],sizeof(f[d]));
    for(int i=l;i<=mid;i++)
    {
        dp(d,i);
    }
    dfs(d+1,mid+1,r);
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d",&cost[i],&val[i],&m[i]);
    }
    dfs(1,1,n);
    scanf("%d",&q);
    while(q--)
    {
        int d,e;
        scanf("%d%d",&d,&e);
        printf("%d\n",ans[d+1][e]);
    }
    return 0;
}
